#!/usr/bin/env node
// bebop i18n — free, open-source autotranslate for docs.
//
// No proprietary APIs, no keys, no telemetry. Talks to a self-hostable OSS engine:
//   • LibreTranslate  (AGPL-3.0)  — default; set LT_URL (e.g. http://localhost:5000)
//   • Argos Translate (Apache-2.0) — if `argos-translate` CLI is on PATH and LT_URL unset
//
// It preserves fenced ``` code blocks, inline `code`, and markdown links verbatim (those are not
// sent for translation), and stamps every output with a MACHINE-DRAFT banner so nobody mistakes a
// generated file for a reviewed translation. Constant Doubt: machine output is NOT authoritative.
//
// Usage:
//   node scripts/i18n-translate.mjs --lang uk            # README.md -> README.uk.md
//   node scripts/i18n-translate.mjs --lang uk --file docs/ARCHITECTURE.md
//   node scripts/i18n-translate.mjs --all uk zh es       # many languages
//
// Self-host the engine (one-time, free):
//   docker run -d -p 5000:5000 libretranslate/libretranslate
//   # or: pip install argos-translate && argos-translate --install en_uk  (offline)

import { readFile, writeFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';

const LT_URL = process.env.LT_URL || 'http://localhost:5000';
const BANNER = (lang) =>
`<!-- MACHINE TRANSLATED DRAFT — generated by scripts/i18n-translate.mjs.\n` +
`     NOT reviewed. Verify technical claims before trusting. Source of truth: the English file. -->\n\n`;

function parseArgs(argv) {
  const a = { langs: [], file: 'README.md', all: false };
  for (let i = 2; i < argv.length; i++) {
    const t = argv[i];
    if (t === '--lang') a.langs.push(argv[++i]);
    else if (t === '--file') a.file = argv[++i];
    else if (t === '--all') { a.all = true; while (argv[i + 1] && !argv[i + 1].startsWith('--')) a.langs.push(argv[++i]); }
  }
  return a;
}

// Split markdown into translatable text vs protected spans (code blocks, inline code, URLs).
function segment(md) {
  const out = [];
  const re = /(```[\s\S]*?```|`[^`]*`|\[[^\]]*\]\([^)]*\))/g;
  let last = 0, m;
  while ((m = re.exec(md))) {
    if (m.index > last) out.push({ t: 'text', v: md.slice(last, m.index) });
    out.push({ t: 'keep', v: m[0] });
    last = re.lastIndex;
  }
  if (last < md.length) out.push({ t: 'text', v: md.slice(last) });
  return out;
}

async function translateText(text, lang) {
  // try LibreTranslate HTTP API
  try {
    const r = await fetch(`${LT_URL}/translate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ q: text, source: 'en', target: lang, format: 'html' }),
    });
    if (r.ok) { const j = await r.json(); if (j.translatedText) return j.translatedText; }
  } catch { /* fall through to argos */ }

  // fallback: argos-translate CLI (offline, Apache-2.0)
  if (existsSync('/usr/bin/argos-translate') || existsSync(`${process.env.HOME}/.local/bin/argos-translate`)) {
    const { execFileSync } = await import('node:child_process');
    try {
      return execFileSync('argos-translate', ['--from', 'en', '--to', lang], { input: text, encoding: 'utf8' });
    } catch { /* ignore */ }
  }
  throw new Error(`No OSS translation backend reachable (LT_URL=${LT_URL}, argos not found)`);
}

async function translateFile(file, lang) {
  const md = await readFile(file, 'utf8');
  const segs = segment(md);
  let translated = '';
  for (const s of segs) {
    if (s.t === 'keep') { translated += s.v; continue; }
    const piece = s.v.trim();
    if (!piece) { translated += s.v; continue; }
    translated += await translateText(s.v, lang);
  }
  const base = file.replace(/\.md$/, '');
  const outPath = `${base}.${lang}.md`;
  await writeFile(outPath, BANNER(lang) + translated);
  console.log(`wrote ${outPath}`);
}

const args = parseArgs(process.argv);
if (!args.langs.length) { console.error('pass --lang <code> or --all <codes...>'); process.exit(2); }
for (const lang of args.langs) await translateFile(args.file, lang);
